from flask import Flask, request, jsonify
import logging

app = Flask(__name__)

# Configure logging
logging.basicConfig(level=logging.DEBUG,
                    format='%(asctime)s - %(levelname)s - %(message)s')

@app.before_request
def log_request_info():
    app.logger.debug('Headers: %s', request.headers)
    if request.method == 'POST' or request.method == 'PUT':
        app.logger.debug('Body: %s', request.get_data(as_text=True))

@app.after_request
def log_response(response):
    app.logger.debug('Response Status: %s', response.status)
    return response

@app.errorhandler(Exception)
def handle_exception(e):
    app.logger.error('Error occurred: %s', str(e))
    return jsonify({'error': 'An error occurred'}), 500

@app.route('/login', methods=['POST'])
def login():
    auth = request.authorization
    if not auth or not auth.username or not auth.password:
        app.logger.error('Failed login attempt - No username or password provided')
        return jsonify({'message': 'Authentication failed'}), 401
    
    # Simulate authentication logic
    if auth.username == 'admin' and auth.password == 'password':
        app.logger.info('User %s logged in successfully', auth.username)
        return jsonify({'message': 'Login successful'}), 200
    else:
        app.logger.error('Failed login attempt - Invalid credentials for user: %s', auth.username)
        return jsonify({'message': 'Authentication failed'}), 401

if __name__ == '__main__':
    app.run(debug=True)